    { "number 9223372036854775807"         , "[9223372036854775807]\n"                   , { tonumber("9223372036854775807") }       , "[9.223372036854776e+18]"                    },
    { "number 9223372036854775808"         , "[9223372036854775808]\n"                   , { 9223372036854775808.0 }                 , "[9.223372036854776e+18]"                    },
    { "object key nfc nfd"                 , '{"é":"NFC","é":"NFD"}'                     , { ["é"] = "NFC", ["é"] = "NFD" }          , '{"é":"NFD","é":"NFC"}'                      },
    { "object key nfd nfc"                 , '{"é":"NFD","é":"NFC"}'                     , { ["é"] = "NFD", ["é"] = "NFC" }          , '{"é":"NFD","é":"NFC"}'                      },
    { "object same key different values"   , '{"a":1,"a":2}'                             , { a = 2 }                                 , '{"a":2}'                                    },
    { "object same key same value"         , '{"a":1,"a":1}'                             , { a = 1 }                                 , '{"a":1}'                                    },
    { "object same key unclear values"     , '{"a":0, "a":-0}\n'                         , { a = 0 }                                 , '{"a":0}'                                    },
    { "string 1 invalid codepoint"         , "[\"\237\160\128\"]"                        , { "\237\160\128" }                        , "[\"\237\160\128\"]"                         },
    { "string 2 invalid codepoints"        , "[\"\237\160\128\237\160\128\"]"            , { "\237\160\128\237\160\128" }            , "[\"\237\160\128\237\160\128\"]"             },
    { "string 3 invalid codepoints"        , "[\"\237\160\128\237\160\128\237\160\128\"]", { "\237\160\128\237\160\128\237\160\128" }, "[\"\237\160\128\237\160\128\237\160\128\"]" },
    { "string with escaped NULL"           , '["A\\u0000B"]'                             , { "A\0B" }                                , '["A\\u0000B"]'                              },
    ---------------------------------------|---------------------------------------------|-----------------------------------------errmsg--------------------------------------------
    { "string 1 escaped invalid codepoint" , '["\\uD800"]'                               , "expected low surrogate after high surrogate at line 1, column 9"          },
    { "string 2 escaped invalid codepoints", '["\\uD800\\uD800"]'                        , "invalid low surrogate at line 1, column 9"                                },
    { "string 3 escaped invalid codepoints", '["\\uD800\\uD800\\uD800"]'                 , "invalid low surrogate at line 1, column 9"                                },
  }

  for i = 1, #tests.transform do
    local name, input, expected_decode, expected_encode = unpack(tests.transform[i])
    local err = not expected_encode and expected_decode or nil

    it("decode() " .. name, function()
      expected_decode = not err and expected_decode or nil
      assert.are_same({ expected_decode, err }, { json.decode(input) })
    end)

    if not err then
      it("encode() " .. name, function()
        assert.are_same({ expected_encode }, { json.encode(expected_decode, { sort_keys = true }) })
      end)
    end
  end

  -- stylua: ignore
  tests.valid = {
    ---------------name-------------|---------------------expected-------------------|-----------------------------------input----------------------------------
    { "array empty indented"        , '[]'                                           , { {}                         , { indent = "  "                        }}},
    { "array empty"                 , "[]"                                           , { {}                                                                   }},
    { "array indented"              , '[\n  1,\n  {\n    "a": 2\n  }\n]'             , { { 1, { a = 2 } }           , { sort_keys = true, indent = "  "      }}},
    { "array nested empty"          , "[[[[]]]]"                                     , { {{{{}}}}                                                             }},
    { "array null and value"        , "[null,1]"                                     , { { json.null, 1 }                                                     }},
    { "array simple"                , "[1,2,3]"                                      , { { 1, 2, 3 }                                                          }},
    { "array two empties"           , "[[],[]]"                                      , { {{},{}}                                                              }},
    { "boolean false"               , "false"                                        , { false                                                                }},
    { "boolean true"                , "true"                                         , { true                                                                 }},
    { "nil top-level"               , "null"                                         , { nil                                                                  }},
    { "null in array"               , "[null]"                                       , { { json.null }                                                        }},
    { "null top-level"              , "null"                                         , { json.null                                                            }},
    { "number above safe integer"   , "9007199254740992"                             , { 9007199254740992                                                     }},
    { "number below safe integer"   , "-9007199254740992"                            , { -9007199254740992                                                    }},
    { "number decimal"              , "12.5"                                         , { 12.5                                                                 }},
    { "number fraction"             , "0.25"                                         , { 0.25                                                                 }},
    { "number integer"              , "42"                                           , { 42                                                                   }},
    { "number max safe integer"     , "9007199254740991"                             , { 9007199254740991                                                     }},
    { "number negative decimal"     , "-12.5"                                        , { -12.5                                                                }},
    { "number negative exponent"    , "-0.045"                                       , { -4.5e-2                                                              }},
    { "number negative integer"     , "-1"                                           , { -1                                                                   }},
    { "number negative safe integer", "-9007199254740991"                            , { -9007199254740991                                                    }},
    { "number positive exponent"    , "1200"                                         , { 1.2e3                                                                }},
    { "number scientific fraction"  , "0.001"                                        , { 1e-3                                                                 }},
    { "number scientific integer"   , "1000000"                                      , { 1e6                                                                  }},
    { "number zero"                 , "0"                                            , { 0                                                                    }},
    { "object array member"         , '{"a":1,"b":[2,3]}'                            , { { a = 1, b = { 2, 3 } }         , { sort_keys = true                }}},
    { "object empty key"            , '{"":1}'                                       , { { [""] = 1}                                                          }},
    { "object indented"             , '{\n  "a": 1,\n  "b": [\n    2,\n    3\n  ]\n}', { { a = 1, b = { 2, 3 } }         , { sort_keys = true, indent = "  " }}},
    { "object multiple null values" , '{"a":null,"b":null}'                          , { { a = json.null, b = json.null }, { sort_keys = true                }}},
    { "object nested null"          , '{"a":{"b":null}}'                             , { { a = { b = json.null } }       , { sort_keys = true                }}},
    { "object null value"           , '{"a":null}'                                   , { { a = json.null }               , { sort_keys = true                }}},
    { "object sorted keys"          , '{"a":1,"b":2}'                                , { { a = 1, b = 2 }                , { sort_keys = true                }}},
    { "object with metatable"       , '{"a":1}'                                      , { setmetatable({ a = 1 }, {})     , { sort_keys = true                }}},
    { "string carriage return"      , [["carriage\rreturn"]]                         , { "carriage\rreturn"                                                   }},
    { "string empty"                , '""'                                           , { ""                                                                   }},
    { "string escape character"     , [["\u001b"]]                                   , { "\27"                                                                }},
    { "string line break"           , [["line\nbreak"]]                              , { "line\nbreak"                                                        }},
    { "string mixed escapes"        , [["mix\\n\t\r"]]                               , { "mix\\n\t\r"                                                         }},
    { "string quotes and backslash" , [["a\"b\\c"]]                                  , { 'a"b\\c'                                                             }},
    { "string slash"                , [["slash/ok"]]                                 , { "slash/ok"                                                           }},
    { "string tab"                  , [["tab\tvalue"]]                               , { "tab\tvalue"                                                         }},
  }

  for i = 1, #tests.valid do
    local name, expected, args = unpack(tests.valid[i] --[[@as {[1]:string,[2]:string,[3]:any,[4]:table?}]], 1, 4)
    it("encode() " .. name, function()
      assert.are_same({ expected }, { json.encode(unpack(args)) })
    end)
  end

  -- stylua: ignore
  tests.invalid = {
      ------name---------------|------------------------input-------------------------|---------------------------errmsg---------------------------
    { "function"               , function() end                                       , "unsupported type: function"                              },
    { "function in array"      , { function() end }                                   , "unsupported type: function"                              },
    { "function in object"     , { a = function() end }                               , "unsupported type: function"                              },
    { "thread"                 , coroutine.create(function() end)                     , "unsupported type: thread"                                },
    { "thread in array"        , { coroutine.create(function() end) }                 , "unsupported type: thread"                                },
    { "thread in object"       , { a = coroutine.create(function() end) }             , "unsupported type: thread"                                },
    { "userdata"               , io.stdout                                            , "unsupported type: userdata"                              },
    { "userdata in array"      , { io.stdout }                                        , "unsupported type: userdata"                              },
    { "userdata in object"     , { a = io.stdout }                                    , "unsupported type: userdata"                              },
    { "mixed table"            , { [1] = "a", b = true }                              , "cannot encode mixed table"                               },
    { "sparse array"           , { [1] = "a", [3] = "c" }                             , "cannot encode sparse array"                              },
    { "non-integer numeric key", { [1.5] = "a" }                                      , "cannot encode table with non-integer numeric key"        },
    { "unsupported key type"   , { [true] = "a" }                                     , "cannot encode table with unsupported key type: boolean"  },
    { "cyclic table"           , (function() local t = {}; t.self = t; return t end)(), "cannot encode cyclic table"                              },
    { "nan"                    , 0 / 0                                                , "cannot encode NaN"                                       },
    { "infinity in array"      , { math.huge }                                        , "cannot encode infinity"                                  },
    { "infinity"               , math.huge                                            , "cannot encode infinity"                                  },
  }

  for i = 1, #tests.invalid do
    local name, input, err = unpack(tests.invalid[i] --[[@as {[1]:string,[2]:any,[3]:string}]], 1, 3)
    it("encode() " .. name, function()
      assert.are_same({ nil, err }, { json.encode(input) })
    end)
  end
end)
